import React, { useState, useEffect } from 'react';
// import Project from '../project/Project';
import data from '../../data/projects.json';
import './Projects.css';


// const projectImage = require('../../assets/images/phi.png');


function Projects({ projContainer, onClick }) {
    let projects = data.projects;
    const [change, setChange] = useState(projContainer);
    const [projectData, setProjectData] = useState(null);

    useEffect(() => {
        if (!change) {
            onClick(change, projectData);
        }
    });

    const handleChange = (evt) => {
        const clickedProjectSlug = evt.currentTarget.getAttribute('data-slug');
        if(clickedProjectSlug === 'coming-soon'){
            return '';
        }else{
            evt.stopPropagation();
            evt.preventDefault();
            setChange(false);
            projects.map((project) => {
                if (clickedProjectSlug === project.slug) {
                    setProjectData(project);
                }
                return '';
            });
        }


        // evt.persist();
        // console.log(evt.currentTarget);
        // console.log(clickedProjectSlug);
    }

    // const apple = (e) => {

    //     e.persist();
    //     console.log(e.currentTarget);

    // }

    const showAllProjects = () => {
        return projects.map((project, i) => {
            if (project) {
                return (<div key={i} data-slug={project.slug} className="individual-project-container" onClick={handleChange}>
                    <div className={`individual-project-background-image ${project.slug}-image`}>
                        {project.slug === 'coming-soon' ? <p className="coming-soon">{project.title}</p> : <p >{project.title}</p>}
                        
                    </div>
                </div>)
            }
            return '';
        })
    }

    return (
        <div className="projects">
            <div className="projects-main-container">
                <div className="projects-content">
                    {showAllProjects()}
                </div>
            </div>

            {/* <h1 onClick={handleChange}>Click</h1> */}

            {/* <div className="fuckk">
                <h1>hello</h1>
                <p>world</p>
            </div> */}
        </div>
    )
}

export default Projects;




